// Source of truth for the DashClaw launch video copy: props/dashclaw-launch.json
// is GENERATED by this script; edit copy here, never in the JSON (it gets clobbered).
// Telemetry is pulled from props/dashclaw-demo.json so the demo act never drifts.
// Voice (brands/dashclaw.json): serious, precise, trustworthy. Verbs: intercept,
// enforce, record, verify. No em dashes, no hype words, no exclamation marks.
import {readFileSync, writeFileSync} from 'node:fs';
import {fileURLToPath} from 'node:url';
import {dirname, join} from 'node:path';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const demo = JSON.parse(readFileSync(join(root, 'props', 'dashclaw-demo.json'), 'utf8'));

const launch = {
  brandId: 'dashclaw',
  kicker: 'dashclaw.io',
  headline: 'Nothing sensitive runs until you allow it',
  demo: {video: demo.video, telemetry: demo.telemetry},
  features: [
    {
      screenshot: 'dashclaw/feature-approvals.png',
      heading: 'Intercept and hold',
      lines: [
        'Sensitive actions are held before they run',
        'Risk scored and bound to the exact command',
        'One click to allow or deny in the inbox',
      ],
    },
    {
      screenshot: 'dashclaw/feature-ledger.png',
      heading: 'Recorded and verified',
      lines: [
        'Every governed action lands in one ledger',
        'Chained to the decision that allowed it',
        'Outcomes verified, spend and risk on the record',
      ],
    },
  ],
  cta: 'Govern your agents at dashclaw.io',
  assets: {
    logoSequence: 'dashclaw/logo-reveal',
    logoFrames: 90,
    loopSequence: null,
    loopFrames: 1,
  },
};

writeFileSync(join(root, 'props', 'dashclaw-launch.json'), JSON.stringify(launch, null, 2) + '\n');
console.log('wrote props/dashclaw-launch.json');
